// src/lang/helpers.ts
var localeMap = {
  en: en_default,
  de: de_default,
  fr: fr_default,
  es: es_default,
  zh: zh_default,
  "zh-cn": zh_default,
  ja: ja_default,
  ko: ko_default,
  pt: pt_default,
  "pt-br": pt_default,
  ru: ru_default
};
var locale = localeMap[window.localStorage.getItem("language") || "en"] || en_default;
function t(str, ...args) {
  let text = locale[str] || en_default[str] || str;
  if (args && args.length > 0) {
    args.forEach((arg, i) => {
      text = text.replace(`%${i + 1}`, arg);
    });
  }
  return text;
}

// src/license.ts
async function verifyLicense(licenseKey) {
  if (!licenseKey || licenseKey.trim().length < 5) {
    return { isValid: false };
  }
  const key = licenseKey.trim();
  try {
    const response = await fetch("https://api.lemonsqueezy.com/v1/licenses/activate", {
      method: "POST",
      headers: {
        "Accept": "application/json",
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        license_key: key,
        instance_name: "Obsidian Plugin"
        // Optional: Name des Geräts
      })
    });
    const data = await response.json();
    if (data.activated === true) {
      return {
        isValid: true,
        message: "License activated successfully.",
        errorType: "none"
      };
    } else if (data.error) {
      return {
        isValid: false,
        message: data.error,
        errorType: "invalid"
      };
    }
    return { isValid: false, errorType: "invalid" };
  } catch (e) {
    console.error("Lemon Squeezy Verification Error:", e);
    return {
      isValid: false,
      message: "Connection error to license server.",
      errorType: "connection"
    };
  }
}

